<?php
namespace Tests\Feature\Hr;use Illuminate\Support\Facades\Artisan;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class HrPhase5ARecruitmentRollbackTest extends TestCase{use RefreshHrDatabase;public function test_recruitment_schema_exists():void{$this->assertTrue(Schema::hasColumns('hr_job_postings',['headcount','requirements','status']));$this->assertTrue(Schema::hasColumns('hr_candidates',['cv_file_id','consent_note','consented_at']));$this->assertTrue(Schema::hasColumns('hr_applications',['current_stage','human_score','decision_reason']));$this->assertTrue(Schema::hasTable('hr_job_offers'));}public function test_rollback_preserves_engagement():void{Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);$this->assertFalse(Schema::hasTable('hr_job_postings'));$this->assertTrue(Schema::hasTable('hr_surveys'));$this->assertTrue(Schema::hasTable('hr_training_courses'));}}
